args.sparql:
SELECT ?country ?countryLabel ?unemploymentRate WHERE { 
  ?country wdt:P463 wd:Q458 . 
  ?country wdt:P2372 ?unemploymentRate . 
  ?country wdt:P6 ?head . 
  ?head wdt:P102 ?party . 
  MINUS { ?party wdt:P90 wd:Q20543 . } 
  ?country rdfs:label ?countryLabel . 
  FILTER(lang(?countryLabel) = "en") 
}

SELECT ?country ?countryLabel ?unemploymentRate WHERE {
  ?country wdt:P463 wd:Q458 .
  ?country wdt:P1198 ?unemploymentRate .
  ?country wdt:P6 ?head .
  ?head wdt:P102 ?party .
  MINUS {
    ?party wdt:P1142 wd:Q20543 .
  }
  ?country rdfs:label ?countryLabel .
  FILTER(LANG(?countryLabel) = 'en')
}

SELECT ?country ?countryLabel ?unemploymentRate WHERE {
  ?country wdt:P463 wd:Q458 .
  ?country wdt:P1198 ?unemploymentRate .
  ?country wdt:P35 ?head .
  ?head wdt:P102 ?party .
  MINUS {
    ?party wdt:P1142 ?ideology .
    ?ideology wdt:P279* wd:Q20543 .
  }
  ?country rdfs:label ?countryLabel .
  FILTER(LANG(?countryLabel) = 'en')
}
